SELECT entity_id, total_vat_collected, report_period
FROM vat_reports
WHERE report_period LIKE 'Q%';

SELECT entity_id, MAX(filing_date) AS recent_filing_date
FROM vat_filing_statuses
GROUP BY entity_id;

SELECT DISTINCT le.entity_name, le.contact_email
FROM legal_entities le
JOIN transactions t ON le.entity_id = t.entity_id;

SELECT entity_id, SUM(total_vat_collected) AS TotalVATCollected
FROM vat_reports
GROUP BY entity_id;

SELECT entity_id, total_vat_collected
FROM vat_reports
WHERE report_period = 'Q1 2023' AND submission_status = 'submitted';

SELECT vat_id, vat_code_description 
FROM vat_codes 
WHERE vat_id = 42;

SELECT entity_name, contact_email
FROM legal_entities
WHERE entity_id IN (SELECT entity_id FROM transactions);

SELECT COUNT(*)
FROM vat_codes
WHERE effective_date >= '2023-01-01' AND effective_date <= '2023-12-31';

SELECT entity_name 
FROM legal_entities
WHERE country_code = 'UK';

SELECT category_name, description
FROM vat_categories
WHERE category_id = 7;

SELECT vat_code_name, l10n_ar_natural_vat, l10n_ar_legal_entity_vat, l10n_ar_other_vat 
FROM vat_codes 
WHERE vat_id IN (SELECT vat_id FROM transactions WHERE entity_id = 100);

SELECT entity_name 
FROM legal_entities 
WHERE entity_id = 123;

SELECT COUNT(DISTINCT entity_id) AS CountOfLegalEntities
FROM transactions
WHERE strftime('%Y-%m', transaction_date) = '2022-01';

SELECT AVG(vat_amount)
FROM transactions
WHERE vat_id = (SELECT vat_id FROM vat_codes WHERE vat_code_name = 'Specific VAT Code Name');

SELECT filing_status AS Filing_Status, filing_date AS Filing_Date
FROM vat_filing_statuses
WHERE entity_id = 12345;
